<?php
namespace App\Services\Customers; use App\Models\Customers\Customer; use App\Models\Customers\CustomerLoyaltyAccount; use App\Models\Customers\CustomerLoyaltyTransaction; use App\Models\User; use App\Services\AuditLogger; use Illuminate\Support\Facades\DB;
class LoyaltyService { public function __construct(private readonly AuditLogger $audit,private readonly CustomerEventService $events){} public function ensureAccount(Customer $customer,User $user):CustomerLoyaltyAccount{return CustomerLoyaltyAccount::firstOrCreate(['company_id'=>$customer->company_id,'customer_id'=>$customer->id],['loyalty_number'=>'LOY-'.str_pad((string)$customer->id,6,'0',STR_PAD_LEFT),'joined_at'=>now()]);} public function adjust(Customer $customer,User $user,int $points,string $description):CustomerLoyaltyTransaction{return DB::transaction(function()use($customer,$user,$points,$description){$account=$this->ensureAccount($customer,$user);$new=$account->points_balance+$points;if($new<0)throw \Illuminate\Validation\ValidationException::withMessages(['points'=>'Points balance cannot become negative.']);$account->update(['points_balance'=>$new,'lifetime_points_earned'=>$account->lifetime_points_earned+max(0,$points),'lifetime_points_redeemed'=>$account->lifetime_points_redeemed+max(0,-$points),'last_activity_at'=>now()]);$customer->update(['loyalty_points_balance'=>$new]);$transaction=CustomerLoyaltyTransaction::create(['company_id'=>$customer->company_id,'customer_id'=>$customer->id,'loyalty_account_id'=>$account->id,'transaction_type'=>$points>=0?'adjustment_credit':'adjustment_debit','points'=>$points,'description'=>$description,'created_by'=>$user->id]);$this->audit->record('customer.loyalty.points_adjusted',$customer,'Customer loyalty points adjusted');$this->events->dispatch('customer.loyalty.points_adjusted',$user,$customer,['points'=>$points]);return $transaction;});} }
